import functools
from collections.abc import Callable
from typing import Any

def log_call[**P, R](func: Callable[P, R]) -> Callable[P, R]:
    @functools.wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        result = func(*args, **kwargs)
        return result
    return wrapper

from dataclasses import dataclass, field
from typing import ClassVar

@dataclass
class ShoppingCart:
    user_id: int
    items: list[str] = field(default_factory=list)
    _total_carts: ClassVar[int] = 0  # Class variable, not an instance field

    def add(self, item: str) -> None:
        self.items.append(item)

@dataclass(frozen=True)
class Point:
    x: float
    y: float

    def distance_to(self, other: "Point") -> float:
        return ((self.x - other.x) ** 2 + (self.y - other.y) ** 2) ** 0.5

from typing import Protocol

class Notifiable(Protocol):
    def send(self, recipient: str, message: str) -> bool: ...

class EmailBackend:
    def send(self, recipient: str, message: str) -> bool:
        # Send via SMTP
        return True

class SMSBackend:
    def send(self, recipient: str, message: str) -> bool:
        # Send via SMS gateway
        return True

def notify_all(backends: list[Notifiable], recipient: str, msg: str) -> None:
    for backend in backends:
        backend.send(recipient, msg)

from contextlib import contextmanager from collections.abc import Generator
@contextmanager def temporary_directory() -> Generator[str, None, None]: import tempfile, shutil path = tempfile.mkdtemp() try: yield path finally: shutil.rmtree(path, ignore_errors=True)
# Usage: cleanup is guaranteed with temporary_directory() as tmp: process_files(tmp)
